VALUES
  ('disabled-6f0ba476-moex-00071', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-114-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '關於民法第 224 條有關債務履行輔助人與第 188 條有關受僱人之民事責 任，下列敘述何者錯誤？', '["民法第224條之使用人，僅限於與債務人有契約關係之受僱人", "民法第188條之受僱人，包含事實上僱用關係之受僱人", "民法第224條之債務人不得舉證免責", "民法第 188 條之僱用人，得舉證無選任監督之過失或其與損害無因果 關係而免責"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:27+00:00", "source_pdf_sha1": "803f0c4dbb29", "answer_pdf_sha1": "6d94596821bd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "305", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00072', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-114-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '甲對乙有新臺幣 1,000 萬元之 A 金錢債權。乙以其對丙之金錢債權供甲 設定權利質權，丁與甲就A債權訂立保證契約，戊以其所有之不動產供 甲設定普通抵押權，以之擔保A債權。另乙積欠甲關於A債權所生屆期 而尚未支付之利息，在此情形下，甲將A債權讓與於庚時，上述何種權 利不當然隨同移轉於庚？', '["已屆期而尚未支付之利息債權", "擔保A債權之保證", "擔保A債權之普通抵押權", "擔保A債權之權利質權"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:27+00:00", "source_pdf_sha1": "803f0c4dbb29", "answer_pdf_sha1": "6d94596821bd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "305", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00073', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-114-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '下列關於租賃契約之敘述，何者錯誤？', '["為保護租用基地建築房屋之承租人之地位，承租人得於契約成立後， 請求出租人為地上權之登記", "基於買賣不破租賃之原則，不動產出租人於將租賃物交付承租人占有 中，將租賃物之所有權移轉讓與第三人時，原承租人之地位並不受影響", "租用基地建築房屋，出租人出賣基地時，承租人有依同樣條件主張優 先承買之權", "租用基地建築房屋，承租人房屋所有權移轉時，其基地租賃契約，對 於房屋受讓人，仍繼續存在"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:27+00:00", "source_pdf_sha1": "803f0c4dbb29", "answer_pdf_sha1": "6d94596821bd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "305", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00074', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-114-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '關於土地利用所涉民法規定之權利，下列敘述何者正確？', '["得將土地設定農育權作為遊覽車停車場之用", "若設定為養殖漁業用之農育權，該權利依民法規定禁止設定抵押權", "若屬耕地租賃情形，於耕地出租人出賣耕地時，承租人有依同樣條件 優先承買之權", "租用土地建築房屋者，基地租賃契約非經登記，不生效力"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:27+00:00", "source_pdf_sha1": "803f0c4dbb29", "answer_pdf_sha1": "6d94596821bd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "305", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00075', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-114-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '下列關於民法第767條規定所有物返還請求權之敘述，何者錯誤？', '["共有人無須經其他共有人之同意，各得單獨行使此請求權，但須為共 有人全體之利益為之", "不動產所有權之登記，縱有無效原因，該登記名義人在未經塗銷或更 正登記前，對於所有人以外之第三人仍得行使該請求權", "依法律規定得行使該請求權之人，不限於所有人，如所有人之破產管 理人、遺產管理人等，亦得行使該請求權", "未登記之不動產所有人之所有物返還請求權，無消滅時效規定之適用， 動產及已登記之不動產則適用之"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:27+00:00", "source_pdf_sha1": "803f0c4dbb29", "answer_pdf_sha1": "6d94596821bd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "305", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00076', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-114-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '甲向乙借錢新臺幣100萬元，除提供土地抵押外，亦提供汽車作為質物， 另找丙當保證人。下列敘述何者錯誤？', '["該借款債權罹於消滅時效後，甲得拒絕還款", "該借款債權罹於消滅時效後，丙得拒絕還款", "該借款債權罹於消滅時效後，再經5年後，乙不得實行抵押權", "該借款債權罹於消滅時效後，再經5年後，乙不得實行質權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:27+00:00", "source_pdf_sha1": "803f0c4dbb29", "answer_pdf_sha1": "6d94596821bd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "305", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00077', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-114-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '下列關於區分地上權之敘述，何者錯誤？', '["為了發揮土地分層立體使用之目的，土地所有人於同一土地上下得同 時設定普通地上權與區分地上權，不受物權排他效力之拘束", "一土地上縱已有普通地上權存在，若土地所有人欲再設定區分地上權 者，無須以取得該普通地上權人之同意為必要", "同一土地上若已先設定普通地上權，其後始成立區分地上權，為發揮區 分地上權之目的，原則上區分地上權應優先於普通地上權之權利行使", "區分地上權人得與其設定之土地上下有使用、收益權利之人，約定相 互間使用收益之限制，包括限制土地所有人對土地之使用收益"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:27+00:00", "source_pdf_sha1": "803f0c4dbb29", "answer_pdf_sha1": "6d94596821bd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "305", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00078', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-114-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '下列關於分別共有物分割請求之敘述，何者錯誤？', '["除法律另有規定或契約另有約定外，各共有人原則上得隨時請求分割", "因物之使用目的不能分割者，各共有人不得請求分割", "共有人得以契約約定，最長5年不得請求分割", "共有人訂有共有物分管契約者，最長得約定10年不得請求分割"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:27+00:00", "source_pdf_sha1": "803f0c4dbb29", "answer_pdf_sha1": "6d94596821bd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "305", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00079', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-114-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '下列何者不適用民法第949條規定之盜贓遺失物回復請求權？', '["由詐欺取得之物", "竊盜之物", "誤取之物", "搶奪之物"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:27+00:00", "source_pdf_sha1": "803f0c4dbb29", "answer_pdf_sha1": "6d94596821bd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "305", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00080', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-114-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '甲有配偶乙，遲未有子。甲偽稱乙同意其尋找代孕，給予丙大筆金錢後 發生性關係。丙未婚懷孕，甲多所照料及支付生活費用，並事先給予生 產後費用，於丙順利產下丁，且按月給付母子生活費用。乙找到丙，警 告其為通姦。丙連夜逃走後，獨力難支，遂將丁出養於戊。下列敘述何 者錯誤？', '["如乙未事前同意或事後宥恕，得就甲之行為訴請裁判離婚", "甲雖未親手照料丁，其支付丙丁之生活費用為對丁有撫育之事實", "甲之行為雖然侵害配偶權，丁仍為甲之準婚生子女", "丙得以法定代理人之身分單獨出養丁，與戊成立書面之收養契約，無 須甲之同意，法院應為收養之認可"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:27+00:00", "source_pdf_sha1": "803f0c4dbb29", "answer_pdf_sha1": "6d94596821bd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "305", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL)
